question:
What will be the output of the following C program?
#include <stdio.h>
int main() {
    int a = 10, b = 20;
    a = a + b;
    b = a - b;
    a = a - b;
    printf("%d %d", a, b);
    return 0;
}

What is the output of the following C code?
#include <stdio.h>
int main() {
    int x = 0;
    for(x=1; x<=5; x++) {
        if(x == 3) continue;
        printf("%d ", x);
    }
    return 0;
}

